function normalizeText(value) {
  return String(value ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

function toBool(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  if (typeof value === 'string') {
    const v = normalizeText(value);
    return ['1', 'true', 'yes', 'sim', 'on'].includes(v);
  }
  return false;
}

function ms(value) {
  if (!value) return null;
  const d = new Date(value);
  const t = d.getTime();
  return Number.isFinite(t) ? t : null;
}

const state = $json;
const nowMs = Date.now();
const gateHours = 72;
const gateMs = gateHours * 60 * 60 * 1000;

const currentLastMessageAtMs = ms(state.current_last_message_at);
const queueGateMs = ms(state.not_before_at);
const computedGateMs = currentLastMessageAtMs ? (currentLastMessageAtMs + gateMs) : null;

const effectiveGateMs = [queueGateMs, computedGateMs]
  .filter((v) => Number.isFinite(v))
  .reduce((max, v) => Math.max(max, v), 0) || null;

const hoursSinceLastMessage = currentLastMessageAtMs
  ? (nowMs - currentLastMessageAtMs) / 36e5
  : null;

const hoursUntilGateOpen = effectiveGateMs
  ? Math.max(0, (effectiveGateMs - nowMs) / 36e5)
  : null;

const snapshotMatches =
  (!state.last_message_id || String(state.last_message_id) === String(state.current_last_message_id ?? '')) &&
  (!state.last_message_hash || String(state.last_message_hash) === String(state.current_last_message_hash ?? '')) &&
  (!state.last_message_actor || normalizeText(state.last_message_actor) === normalizeText(state.current_last_message_actor ?? '')) &&
  (!state.snapshot_last_stage_name || normalizeText(state.snapshot_last_stage_name) === normalizeText(state.current_stage_name ?? ''));

const closedLike = Boolean(state.is_closed);
const hasHuman = Array.isArray(state.tags) && state.tags.some((t) =>
  normalizeText(t).includes('atendimento_humano') ||
  normalizeText(t).includes('humano') ||
  normalizeText(t).includes('consultora')
);

const hasDone = Array.isArray(state.tags) && state.tags.some((t) =>
  normalizeText(t).includes('resgate_cancelado') ||
  normalizeText(t).includes('resgate_concluido')
);

let should_execute_now = false;
let should_reschedule = false;
let should_cancel = false;

let cancel_reason = null;
let reschedule_reason = null;

if (!state.lead_id) {
  should_cancel = true;
  cancel_reason = 'missing_lead_id';
} else if (closedLike) {
  should_cancel = true;
  cancel_reason = 'closed';
} else if (hasHuman) {
  should_cancel = true;
  cancel_reason = 'human_handling';
} else if (hasDone) {
  should_cancel = true;
  cancel_reason = 'already_finished';
} else if (Number(state.current_status_id ?? 0) !== Number(state.snapshot_status_id ?? state.status_id ?? 0)) {
  should_cancel = true;
  cancel_reason = 'stage_changed';
} else if (Number(state.pipeline_id ?? 0) !== Number(state.queue_pipeline_id ?? 0)) {
  should_cancel = true;
  cancel_reason = 'pipeline_changed';
} else if (!currentLastMessageAtMs) {
  should_cancel = true;
  cancel_reason = 'missing_last_message';
} else if (!effectiveGateMs || nowMs < effectiveGateMs) {
  should_reschedule = true;
  reschedule_reason = 'recent_message';
} else if (!snapshotMatches) {
  should_reschedule = true;
  reschedule_reason = 'snapshot_changed';
} else {
  should_execute_now = true;
}

const nextExecuteAtMs = should_reschedule
  ? (effectiveGateMs ?? (currentLastMessageAtMs + gateMs))
  : null;

const nextExecuteAt = nextExecuteAtMs ? new Date(nextExecuteAtMs).toISOString() : null;

return [{
  json: {
    ...state,
    should_execute_now,
    should_reschedule,
    should_cancel,
    decision: should_execute_now ? 'execute' : (should_reschedule ? 'reschedule' : 'cancel'),
    cancel_reason,
    reschedule_reason,
    next_execute_at: nextExecuteAt,
    next_not_before_at: nextExecuteAt,
    hours_since_last_message: hoursSinceLastMessage,
    hours_until_gate_open: hoursUntilGateOpen,
    snapshot_matches: snapshotMatches,
    effective_gate_at: effectiveGateMs ? new Date(effectiveGateMs).toISOString() : null,
    time_gate_open: Boolean(effectiveGateMs && nowMs >= effectiveGateMs),
  },
}];

function normalizeText(value) {
  return String(value ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

function sql(value) {
  if (value === null || value === undefined || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function sqlTz(value) {
  const q = sql(value);
  return q === 'NULL' ? 'NULL' : `${q}::timestamptz`;
}

function sqlNum(value) {
  const n = Number(value);
  return Number.isFinite(n) ? String(n) : 'NULL';
}

const row = $json;
const rescheduleAt = row.next_execute_at || row.next_not_before_at || row.effective_gate_at || null;
const nextReason = row.reschedule_reason || 'recent_message';

const sqlInsertHistory = `
INSERT INTO public.rescue_history (
  queue_key,
  lead_id,
  attempt,
  action,
  result,
  details,
  last_message_id,
  last_message_at,
  last_message_actor,
  last_message_hash,
  not_before_at,
  snapshot_last_stage_name,
  snapshot_status_id,
  created_at
) VALUES (
  ${sql(row.queue_key)},
  ${sqlNum(row.lead_id)},
  ${sqlNum(row.attempt)},
  'rescheduled',
  'pending',
  ${sql(`reason=${nextReason} | next_execute_at=${rescheduleAt || 'null'} | hours_until_gate_open=${row.hours_until_gate_open ?? 'null'}`)},
  ${sql(row.current_last_message_id ?? row.last_message_id)},
  ${sqlTz(row.current_last_message_at ?? row.last_message_at)},
  ${sql(row.current_last_message_actor ?? row.last_message_actor)},
  ${sql(row.current_last_message_hash ?? row.last_message_hash)},
  ${sqlTz(rescheduleAt)},
  ${sql(row.current_stage_name ?? row.snapshot_last_stage_name ?? row.last_stage_name ?? '')},
  ${sqlNum(row.current_status_id ?? row.snapshot_status_id ?? row.status_id)},
  NOW()
);
`.trim();

const sqlUpdateQueue = `
UPDATE public.rescue_queue
SET
  status = 'pending',
  execute_at = ${sqlTz(rescheduleAt)},
  not_before_at = ${sqlTz(rescheduleAt)},
  block_reason = ${sql(nextReason)},
  last_event_type = 'rescue_rescheduled',
  last_stage_name = ${sql(row.current_stage_name ?? row.snapshot_last_stage_name ?? row.last_stage_name ?? '')},
  last_message_id = ${sql(row.current_last_message_id ?? row.last_message_id)},
  last_message_at = ${sqlTz(row.current_last_message_at ?? row.last_message_at)},
  last_message_actor = ${sql(row.current_last_message_actor ?? row.last_message_actor)},
  last_message_hash = ${sql(row.current_last_message_hash ?? row.last_message_hash)},
  snapshot_last_stage_name = ${sql(row.current_stage_name ?? row.snapshot_last_stage_name ?? row.last_stage_name ?? '')},
  snapshot_status_id = ${sqlNum(row.current_status_id ?? row.snapshot_status_id ?? row.status_id)},
  updated_at = NOW()
WHERE queue_key = ${sql(row.queue_key)};
`.trim();

return [{
  json: {
    ...row,
    reschedule_at: rescheduleAt,
    sql_insert_history_rescheduled: sqlInsertHistory,
    sql_update_queue_rescheduled: sqlUpdateQueue,
  },
}];

function normalizeText(value) {
  return String(value ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

function parseMaybeJson(value) {
  if (!value) return {};

  if (typeof value === 'string') {
    try {
      return JSON.parse(value);
    } catch {
      return {};
    }
  }

  if (
    typeof value === 'object' &&
    value.data &&
    typeof value.data === 'string'
  ) {
    try {
      return JSON.parse(value.data);
    } catch {
      return value;
    }
  }

  return value;
}

function extractTags(src) {
  const raw = src?._embedded?.tags ?? src?.tags ?? [];
  const list = Array.isArray(raw) ? raw : (raw ? [raw] : []);

  return list
    .map((t) => normalizeText(t?.name ?? t?.title ?? t?.tag_name ?? t))
    .filter(Boolean);
}

function getCustomFieldValue(src, names) {
  const wanted = Array.isArray(names)
    ? names.map(normalizeText)
    : [normalizeText(names)];

  const fields = Array.isArray(src?.custom_fields_values)
    ? src.custom_fields_values
    : [];

  for (const field of fields) {
    const fieldName = normalizeText(
      field?.field_name ?? field?.field_code ?? ''
    );

    if (wanted.some((n) => fieldName.includes(n))) {
      const rawValue = Array.isArray(field?.values)
        ? field.values[0]?.value
        : field?.value;

      return rawValue ?? null;
    }
  }

  return null;
}

function toBool(value) {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;

  if (typeof value === 'string') {
    return ['1', 'true', 'yes', 'sim', 'on'].includes(
      normalizeText(value)
    );
  }

  return false;
}

function simpleHash(text) {
  const s = normalizeText(text);

  let hash = 0;

  for (let i = 0; i < s.length; i++) {
    hash = Math.imul(31, hash) + s.charCodeAt(i) | 0;
  }

  return (hash >>> 0).toString(16);
}

/* ===================================================================== */
/* FONTES DE DADOS                                                       */
/* ===================================================================== */

const queue = $items("loop data")[0].json;

const leadRaw = parseMaybeJson(
  $items("Pega Lead do Kommo")[0].json
);

const statusesRaw = parseMaybeJson(
  $items("Pega Pipeline Statuses")[0].json
);

/* ===================================================================== */

const lead =
  leadRaw?.data && typeof leadRaw.data === 'object'
    ? leadRaw.data
    : leadRaw;

const statusesContainer =
  statusesRaw?.data && typeof statusesRaw.data === 'object'
    ? statusesRaw.data
    : statusesRaw;

const statuses = Array.isArray(statusesContainer)
  ? statusesContainer
  : statusesContainer?._embedded?.statuses ??
    statusesContainer?.statuses ??
    [];

/* ===================================================================== */
/* ESTADO ATUAL DO LEAD                                                  */
/* ===================================================================== */

const currentLeadId =
  Number(lead?.id ?? queue.lead_id ?? 0) || null;

const currentPipelineId =
  Number(lead?.pipeline_id ?? queue.pipeline_id ?? 0) || null;

const currentStatusId =
  Number(lead?.status_id ?? queue.status_id ?? 0) || null;

const statusMatch =
  statuses.find(
    (s) =>
      Number(s?.id ?? s?.status_id ?? 0) === currentStatusId
  ) ?? null;

const currentStageName =
  statusMatch?.name ??
  lead?.status_name ??
  queue.last_stage_name ??
  '';

/* ===================================================================== */

const tags = extractTags(lead);

const customLastMessageText = String(
  getCustomFieldValue(
    lead,
    [
      'ultima msg',
      'ultima mensagem',
      'última msg',
      'última mensagem',
    ]
  ) ?? ''
);

const customAiMessageText = String(
  getCustomFieldValue(
    lead,
    ['mensagem ia', 'mensagem ai']
  ) ?? ''
);

const rawPararIa = getCustomFieldValue(
  lead,
  ['parar ia']
);

const pararIa = toBool(rawPararIa);

/* ===================================================================== */

const currentLastMessageText =
  customLastMessageText || customAiMessageText || '';

const currentLastMessageHash = simpleHash(
  currentLastMessageText ||
    currentStageName ||
    String(currentStatusId ?? '')
);

const currentLastMessageId = lead?.updated_at
  ? String(lead.updated_at)
  : null;

const currentLastMessageAt = lead?.updated_at
  ? new Date(Number(lead.updated_at) * 1000).toISOString()
  : null;

/* ===================================================================== */

let currentLastMessageActor = 'lead';

if (
  currentLastMessageText &&
  customAiMessageText &&
  normalizeText(currentLastMessageText) ===
    normalizeText(customAiMessageText)
) {
  currentLastMessageActor = 'ia';
} else if (pararIa) {
  currentLastMessageActor = 'human';
} else if (
  tags.some((t) => t.includes('em atendimento ia'))
) {
  currentLastMessageActor = 'ia';
}

/* ===================================================================== */

const closedLike =
  /vendid|vendido|fechad|perdid|cancelad|arquivad|encerrad/i.test(
    normalizeText(currentStageName)
  );

const isClosed =
  Boolean(lead?.is_deleted) ||
  Boolean(lead?.closed_at) ||
  closedLike;

/* ===================================================================== */

return [
  {
    json: {
      phase: 'before_wait',

      /* ============================================================= */
      /* Snapshot salvo na fila                                        */
      /* ============================================================= */

      queue_key: queue.queue_key ?? null,
      attempt: Number(queue.attempt ?? 0),

      execute_at: queue.execute_at ?? null,
      not_before_at: queue.not_before_at ?? null,

      block_reason: queue.block_reason ?? null,

      last_event_type: queue.last_event_type ?? null,

      last_stage_name: queue.last_stage_name ?? '',

      snapshot_last_stage_name:
        queue.snapshot_last_stage_name ??
        queue.last_stage_name ??
        '',

      snapshot_status_id:
        Number(
          queue.snapshot_status_id ??
            queue.status_id ??
            0
        ) || null,

      last_message_id:
        queue.last_message_id ?? null,

      last_message_at:
        queue.last_message_at ?? null,

      last_message_actor:
        queue.last_message_actor ?? null,

      last_message_hash:
        queue.last_message_hash ?? null,

      queue_pipeline_id:
        Number(queue.pipeline_id ?? 0) || null,

      queue_status_id:
        Number(queue.status_id ?? 0) || null,

      rescue_type:
        queue.rescue_type ?? null,

      rescue_label:
        queue.rescue_label ?? null,

      wait_hours:
        Number(queue.wait_hours ?? 0),

      max_attempts:
        Number(queue.max_attempts ?? 1),

      /* ============================================================= */
      /* Estado atual do Kommo                                         */
      /* ============================================================= */

      lead_id: currentLeadId,

      lead_name:
        lead?.name ?? '',

      pipeline_id:
        currentPipelineId,

      current_status_id:
        currentStatusId,

      current_stage_name:
        currentStageName,

      trigger_status_id: null,
      trigger_stage_name: '',

      event_type:
        queue.last_event_type ??
        'cron',

      tags,

      is_closed: isClosed,

      closed_like:
        closedLike,

      updated_at:
        lead?.updated_at ?? null,

      pending_lock: null,

      /* ============================================================= */
      /* Snapshot atual da conversa                                    */
      /* ============================================================= */

      current_last_message_id:
        currentLastMessageId,

      current_last_message_at:
        currentLastMessageAt,

      current_last_message_actor:
        currentLastMessageActor,

      current_last_message_hash:
        currentLastMessageHash,

      current_last_message_text:
        currentLastMessageText,

      current_ai_message_text:
        customAiMessageText || null,

      current_parar_ia:
        pararIa,

      current_last_message_signature:
        `${currentLastMessageActor}:${currentLastMessageHash}`,

      /* ============================================================= */

      lead_full: lead,

      pipeline_statuses:
        statuses,

      received_at: null,

      raw_event: 'cron',
    },
  },
];

function normalizeText(value) {
  return String(value ?? '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

function sql(value) {
  if (value === null || value === undefined || value === '') return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

