const state = $json;
const rescueTypeUpper = normalizeText(state.rescue_type || 'general')
  .replace(/[^a-z0-9]+/g, '_')
  .replace(/^_|_$/g, '')
  .toUpperCase() || 'GENERAL';

const currentAttempt = Math.max(1, Number(state.attempt || 0) + 1);
const canRetry = currentAttempt < Math.max(1, Number(state.max_attempts || 1));
const nextExecuteAt = canRetry
  ? new Date(Date.now() + Math.max(1, Number(state.wait_hours || 1)) * 60 * 60 * 1000).toISOString()
  : null;

const patchBody = {
  updated_by: 0,
  tags_to_add: [
    { name: 'RESGATE_EM_EXECUCAO' },
    { name: `RESGATE_EM_EXECUCAO_${rescueTypeUpper}` },
    { name: `RESGATE_TENTATIVA_${currentAttempt}` },
  ],
  tags_to_delete: [
    { name: 'RESGATE_PENDENTE' },
    { name: `RESGATE_PENDENTE_${rescueTypeUpper}` },
  ],
};

const sqlInsertHistory = `
INSERT INTO public.rescue_history (
  queue_key,
  lead_id,
  attempt,
  action,
  result,
  details,
  last_message_id,
  last_message_at,
  last_message_actor,
  last_message_hash,
  not_before_at,
  snapshot_last_stage_name,
  snapshot_status_id,
  created_at
) VALUES (
  ${sql(state.queue_key)},
  ${sqlNum(state.lead_id)},
  ${currentAttempt},
  'dispatch',
  'sent',
  ${sql(`executed_at=${new Date().toISOString()} | next_execute_at=${nextExecuteAt || 'none'} | rescue_type=${state.rescue_type}`)},
  ${sql(state.current_last_message_id ?? state.last_message_id)},
  ${sqlTz(state.current_last_message_at ?? state.last_message_at)},
  ${sql(state.current_last_message_actor ?? state.last_message_actor)},
  ${sql(state.current_last_message_hash ?? state.last_message_hash)},
  ${sqlTz(nextExecuteAt)},
  ${sql(state.current_stage_name ?? state.snapshot_last_stage_name ?? state.last_stage_name ?? '')},
  ${sqlNum(state.current_status_id ?? state.snapshot_status_id ?? state.status_id)},
  NOW()
);
`.trim();

const sqlUpdateQueue = `
UPDATE public.rescue_queue
SET
  attempt = ${currentAttempt},
  status = ${sql(canRetry ? 'pending' : 'exhausted')},
  execute_at = ${sqlTz(nextExecuteAt)},
  not_before_at = ${sqlTz(nextExecuteAt)},
  block_reason = NULL,
  last_event_type = ${sql('rescue_dispatched')},
  last_stage_name = ${sql(state.current_stage_name ?? state.snapshot_last_stage_name ?? state.last_stage_name ?? '')},
  last_message_id = ${sql(state.current_last_message_id ?? state.last_message_id)},
  last_message_at = ${sqlTz(state.current_last_message_at ?? state.last_message_at)},
  last_message_actor = ${sql(state.current_last_message_actor ?? state.last_message_actor)},
  last_message_hash = ${sql(state.current_last_message_hash ?? state.last_message_hash)},
  snapshot_last_stage_name = ${sql(state.current_stage_name ?? state.snapshot_last_stage_name ?? state.last_stage_name ?? '')},
  snapshot_status_id = ${sqlNum(state.current_status_id ?? state.snapshot_status_id ?? state.status_id)},
  updated_at = NOW()
WHERE queue_key = ${sql(state.queue_key)};
`.trim();

return [{
  json: {
    ...state,
    attempt_now: currentAttempt,
    next_execute_at: nextExecuteAt,
    next_status: canRetry ? 'pending' : 'exhausted',
    patch_body: patchBody,
    sql_insert_history_dispatched: sqlInsertHistory,
    sql_update_queue_dispatched: sqlUpdateQueue,
  },
}];

