    sql_insert_history_cancelled: sqlInsertHistory,
    sql_update_queue_cancelled: sqlCancelQueue,
  },
}];

const now = new Date();

const hour = now.getHours(); // 0-23

const isBusinessHours = hour >= 7 && hour < 21;

return [{
  json: {
    ...$json,
    current_hour: hour,
    is_business_hours: isBusinessHours,
    current_time: now.toISOString(),
  }
}];
